import{_ as a,o as t,c as i,a2 as n}from"./chunks/framework.CHeM0PsO.js";const h=JSON.parse('{"title":"RFC 0067 — Product-led docs site and instance directory","description":"","frontmatter":{},"headers":[],"relativePath":"rfcs/0067-product-led-docs-site.md","filePath":"rfcs/0067-product-led-docs-site.md"}'),o={name:"rfcs/0067-product-led-docs-site.md"};function s(r,e,l,d,c,p){return t(),i("div",null,[...e[0]||(e[0]=[n(`<h1 id="rfc-0067-—-product-led-docs-site-and-instance-directory" tabindex="-1">RFC 0067 — Product-led docs site and instance directory <a class="header-anchor" href="#rfc-0067-—-product-led-docs-site-and-instance-directory" aria-label="Permalink to &quot;RFC 0067 — Product-led docs site and instance directory&quot;">​</a></h1><p><strong>Status:</strong> Implemented<br><strong>Date:</strong> July 2026<br><strong>Author:</strong> kasunben<br><strong>Scope:</strong> <code>apps/docs</code>, public content under <code>docs/</code>; builds on RFC 0037<br><strong>Incorporated into plan:</strong> Yes — epic task 16.4 (completed).</p><hr><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>Evolve the Sovereign VitePress site from a technical landing page into one coherent public site with three layers: product education, discovery of hosted Sovereign instances, and audience-oriented technical documentation.</p><p>The site will consistently describe Sovereign as:</p><blockquote><p>Sovereign is an open-source workspace runtime for hosting private, multi-user apps on infrastructure you control.</p></blockquote><p>Visitors will be able to understand the product, find an independently operated instance, host their own instance, build a custom app on Sovereign&#39;s shared platform capabilities, or enter the technical documentation without first learning the repository architecture.</p><h2 id="motivation" tabindex="-1">Motivation <a class="header-anchor" href="#motivation" aria-label="Permalink to &quot;Motivation&quot;">​</a></h2><p>The current homepage primarily explains implementation characteristics: self-hosting, plugin architecture, databases, SDK contracts, and the design system. Those details are useful to operators and developers, but the page does not first establish what Sovereign enables for a person, team, household, organization, or community.</p><p>Three gaps follow from that emphasis:</p><ol><li>A first-time visitor does not get a concise product explanation or a visual understanding of the workspace.</li><li>A person who wants to use Sovereign, rather than operate or extend it, has no clear path to an available instance.</li><li>User, operator, app-developer, architecture, and contributor material share a technical navigation model instead of beginning from each audience&#39;s task.</li></ol><p>Sovereign also needs to communicate that extensibility is more than installing existing apps. A developer can build a purpose-specific app and reuse platform foundations for identity, app-scoped data, storage, UI, and security instead of assembling those capabilities independently. Public copy must still distinguish shipped, in-development, planned, and exploratory capabilities.</p><h2 id="goals-and-non-goals" tabindex="-1">Goals and non-goals <a class="header-anchor" href="#goals-and-non-goals" aria-label="Permalink to &quot;Goals and non-goals&quot;">​</a></h2><h3 id="goals" tabindex="-1">Goals <a class="header-anchor" href="#goals" aria-label="Permalink to &quot;Goals&quot;">​</a></h3><ul><li>Make Sovereign understandable to a non-technical visitor within one minute.</li><li>Establish <strong>open-source workspace runtime</strong> as the public product category.</li><li>Give users, operators, and app developers distinct starting paths.</li><li>Explain the instance, operator, user, app, and plugin relationship.</li><li>Introduce a curated hosted-instance directory with explicit trust boundaries.</li><li>Separate the public product roadmap from the internal engineering queue.</li><li>Preserve existing technical documentation depth, search, and stable routes.</li><li>Keep <code>docs/</code> as the content source and VitePress as the site generator.</li></ul><h3 id="non-goals" tabindex="-1">Non-goals <a class="header-anchor" href="#non-goals" aria-label="Permalink to &quot;Non-goals&quot;">​</a></h3><ul><li>Changing the Sovereign runtime, SDK, manifest, or deployment architecture.</li><li>Replacing VitePress or creating a separate marketing application.</li><li>Building an automated instance registry, uptime monitor, or open submission service in the first release.</li><li>Publishing internal task IDs or speculative dates as product commitments.</li><li>Adding third-party analytics by default.</li><li>Changing the internal engineering roadmap beyond recording this completed documentation task.</li></ul><h2 id="current-state-what-this-builds-on" tabindex="-1">Current state (what this builds on) <a class="header-anchor" href="#current-state-what-this-builds-on" aria-label="Permalink to &quot;Current state (what this builds on)&quot;">​</a></h2><ul><li>RFC 0037 established <code>apps/docs</code> as a VitePress site reading directly from <code>docs/</code>, with local search and GitHub Pages deployment (<code>docs/rfcs/0037-vitepress-docs-site.md</code>).</li><li><code>docs/index.md</code> uses VitePress&#39;s built-in home layout and leads with technical feature tiles.</li><li><code>apps/docs/.vitepress/config.ts</code> exposes Guide, Plugin Dev, Design System, RFCs, and GitHub in the global navigation and uses one shared technical sidebar.</li><li><code>apps/docs/.vitepress/theme/index.ts</code> extends the default VitePress theme and already provides a stable custom-theme boundary.</li><li><code>docs/self-hosting.md</code> is the current general operator entry point.</li><li><code>ROADMAP.md</code> is an internal chronological task queue and is already excluded from the public VitePress build.</li><li><code>https://sovereign.openfs.io/</code> is the first candidate hosted instance, but its operator, intended audience, registration policy, support path, and policy links must be verified before the directory presents them as facts.</li></ul><h2 id="proposed-design" tabindex="-1">Proposed design <a class="header-anchor" href="#proposed-design" aria-label="Permalink to &quot;Proposed design&quot;">​</a></h2><h3 id="positioning-and-terminology" tabindex="-1">Positioning and terminology <a class="header-anchor" href="#positioning-and-terminology" aria-label="Permalink to &quot;Positioning and terminology&quot;">​</a></h3><p>Use the primary definition in the homepage introduction, product overview, metadata, and social previews. Supporting copy should communicate operation, use, and extensibility:</p><blockquote><p>Run your own instance, invite users, and install or build the apps your community needs. Sovereign provides shared foundations for identity, data, storage, and security, so app builders can focus on custom workflows while operators retain control of their infrastructure and data.</p></blockquote><p>Use these terms consistently:</p><table tabindex="0"><thead><tr><th>Context</th><th>Term</th></tr></thead><tbody><tr><td>Public product category</td><td>Open-source workspace runtime</td></tr><tr><td>Technical description</td><td>Modular, self-hostable workspace runtime</td></tr><tr><td>Deployed installation</td><td>Sovereign instance</td></tr><tr><td>User environment</td><td>Workspace</td></tr><tr><td>User-facing capabilities</td><td>Apps</td></tr><tr><td>Architecture and APIs</td><td>Plugins</td></tr><tr><td>Responsible host</td><td>Operator</td></tr></tbody></table><p>&quot;Suite&quot; is not the primary category because it suggests a fixed application bundle. Marketing pages use <strong>app</strong>; manifests, SDKs, source code, and developer documentation retain <strong>plugin</strong>.</p><h3 id="three-layer-information-architecture" tabindex="-1">Three-layer information architecture <a class="header-anchor" href="#three-layer-information-architecture" aria-label="Permalink to &quot;Three-layer information architecture&quot;">​</a></h3><p>The global navigation becomes:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Product   Instances   Get Started   Roadmap   Docs   GitHub</span></span></code></pre></div><p>The public route model is:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/</span></span>
<span class="line"><span>├── product</span></span>
<span class="line"><span>│   ├── why-sovereign</span></span>
<span class="line"><span>│   ├── how-it-works</span></span>
<span class="line"><span>│   ├── features</span></span>
<span class="line"><span>│   └── apps</span></span>
<span class="line"><span>├── instances</span></span>
<span class="line"><span>├── get-started</span></span>
<span class="line"><span>│   ├── users</span></span>
<span class="line"><span>│   ├── operators</span></span>
<span class="line"><span>│   └── developers</span></span>
<span class="line"><span>├── product-roadmap</span></span>
<span class="line"><span>└── docs</span></span>
<span class="line"><span>    ├── users</span></span>
<span class="line"><span>    ├── operators</span></span>
<span class="line"><span>    ├── developers</span></span>
<span class="line"><span>    ├── architecture</span></span>
<span class="line"><span>    └── contributing</span></span></code></pre></div><p><code>/product-roadmap</code> is deliberately separate from the excluded internal <code>ROADMAP.md</code> route.</p><h3 id="product-education-layer" tabindex="-1">Product education layer <a class="header-anchor" href="#product-education-layer" aria-label="Permalink to &quot;Product education layer&quot;">​</a></h3><p>The homepage answers four questions in order: what Sovereign is, who it is for, why it matters, and what the visitor can do next. It uses a real or faithful product visual in the first viewport and provides three actions: explore the product, try an instance, and host an instance.</p><p>Homepage content then explains:</p><ol><li>The instance, operator, user, and app model.</li><li>What users can do with currently available apps.</li><li>What operators control and must maintain.</li><li>How developers build purpose-specific apps on shared platform foundations.</li><li>The concrete privacy and ownership model, including operator trust.</li><li>The available instance and role-based next steps.</li></ol><p>Product pages expand the explanation without forcing visitors into API or deployment detail. Every marketed capability uses one of four status labels: <strong>Available</strong>, <strong>In development</strong>, <strong>Planned</strong>, or <strong>Exploring</strong>. A claim should link to evidence such as a guide, screenshot, release, source, or roadmap item.</p><h3 id="hosted-instance-directory" tabindex="-1">Hosted-instance directory <a class="header-anchor" href="#hosted-instance-directory" aria-label="Permalink to &quot;Hosted-instance directory&quot;">​</a></h3><p><code>/instances</code> is a manually curated directory. Listings are maintained as reviewed structured data and include:</p><ul><li>Instance name and canonical HTTPS URL.</li><li>Operator identity and optional operator information URL.</li><li>Intended audience or community.</li><li>Access policy: open, approval required, invite only, or demonstration.</li><li>Available user-facing apps.</li><li>Privacy, terms, and support links.</li><li>Last verified date and listing status.</li><li>Optional broad region and public version compatibility.</li></ul><p>Each page states that listed instances are independently operated and are not audited, endorsed, guaranteed, or supported by the Sovereign project unless explicitly stated. The operator controls accounts, policies, apps, retention, backups, infrastructure, and support.</p><p>The first directory release may identify <code>sovereign.openfs.io</code> as a candidate or demonstration endpoint while verification is incomplete. It must not infer open registration solely from a visible account-creation link.</p><h3 id="role-based-getting-started" tabindex="-1">Role-based getting started <a class="header-anchor" href="#role-based-getting-started" aria-label="Permalink to &quot;Role-based getting started&quot;">​</a></h3><p><code>/get-started</code> asks the visitor to choose a goal:</p><ul><li><strong>Use Sovereign:</strong> Find an instance, understand operator trust, obtain an account, install the instance as a PWA, enable supported device features, and learn the workspace.</li><li><strong>Host Sovereign:</strong> Evaluate requirements, deploy a test instance, and follow production guidance for TLS, email, storage, backups, upgrades, and security.</li><li><strong>Build an app:</strong> Create a plugin, use platform capabilities through the SDK, test it locally, and prepare it for distribution.</li></ul><h3 id="technical-documentation-layer" tabindex="-1">Technical documentation layer <a class="header-anchor" href="#technical-documentation-layer" aria-label="Permalink to &quot;Technical documentation layer&quot;">​</a></h3><p><code>/docs</code> becomes an audience-oriented hub with five entrances: use Sovereign, operate Sovereign, build apps, understand Sovereign, and contribute. Existing technical pages remain canonical during the first implementation.</p><p>Operator documentation can later be decomposed into quickstart, production, configuration, users and access, apps, backups, upgrades, security, and troubleshooting. <code>/self-hosting</code> remains valid as a compatibility route or redirect throughout that migration.</p><p>RFCs remain available and searchable but are not a primary user or operator path. Internal plans, epics, and the engineering roadmap remain excluded from the public build.</p><h3 id="installed-pwa-experience" tabindex="-1">Installed PWA experience <a class="header-anchor" href="#installed-pwa-experience" aria-label="Permalink to &quot;Installed PWA experience&quot;">​</a></h3><p>The user path documents how to install a specific Sovereign instance on iOS, Android, and supported desktop browsers. It distinguishes the installed instance from a global app and covers standalone launch, per-device Web Push opt-in, notification preferences, updates, offline fallback behavior, and common recovery steps.</p><p>The guide makes the operator dependency explicit: production installation and Web Push require HTTPS, push controls appear only when the operator configures VAPID, and iOS push requires an installed Home Screen PWA on iOS/iPadOS 16.4 or later. It does not describe Sovereign as fully offline-first; individual apps must document any offline data and synchronization guarantees they provide.</p><h3 id="public-product-roadmap" tabindex="-1">Public product roadmap <a class="header-anchor" href="#public-product-roadmap" aria-label="Permalink to &quot;Public product roadmap&quot;">​</a></h3><p><code>/product-roadmap</code> presents outcome-based horizons:</p><ul><li>Available now</li><li>Being built</li><li>Next</li><li>Later</li><li>Exploring</li></ul><p>It does not expose internal task IDs, roadmap slot versions, branch names, or uncommitted dates. It links to RFCs or GitHub for technical context and states that plans can change. The internal engineering roadmap remains authoritative for sequencing.</p><h3 id="visual-and-content-system" tabindex="-1">Visual and content system <a class="header-anchor" href="#visual-and-content-system" aria-label="Permalink to &quot;Visual and content system&quot;">​</a></h3><ul><li>Extend the existing VitePress theme rather than fork it.</li><li>Use real product imagery or faithful UI captures with safe demonstration data.</li><li>Keep screenshots inspectable and provide meaningful alt text.</li><li>Use full-width content bands and restrained repeated items; avoid nested card layouts and decorative gradients.</li><li>Keep technical pages quiet, readable, and optimized for scanning.</li><li>Support light and dark themes, keyboard navigation, reduced motion, mobile layouts, and WCAG 2.1 AA contrast.</li><li>Avoid runtime package imports in the docs theme. Docs components may express the Sovereign visual language through local CSS tokens.</li></ul><h3 id="data-and-build-boundaries" tabindex="-1">Data and build boundaries <a class="header-anchor" href="#data-and-build-boundaries" aria-label="Permalink to &quot;Data and build boundaries&quot;">​</a></h3><p>The first implementation remains static and auditable:</p><ul><li>Product, roadmap, and directory content are reviewed repository files.</li><li>The site does not depend on a live Sovereign API at build or request time.</li><li>Structured instance data is validated before publication when the directory moves beyond a candidate listing.</li><li>Existing VitePress local search remains the search provider.</li><li>Route compatibility and internal-link validation are release requirements.</li><li>No Dockerfiles, Compose files, runtime ports, environment variables, or standalone runtime output are changed.</li></ul><h3 id="accessibility-performance-and-privacy" tabindex="-1">Accessibility, performance, and privacy <a class="header-anchor" href="#accessibility-performance-and-privacy" aria-label="Permalink to &quot;Accessibility, performance, and privacy&quot;">​</a></h3><ul><li>Target WCAG 2.1 AA and complete keyboard operation.</li><li>Use semantic headings, landmarks, focus styles, skip links, useful image alt text, and adjacent text explanations for diagrams.</li><li>Give images explicit dimensions and responsive formats.</li><li>Target mobile Lighthouse scores of at least 90 for performance and 100 for accessibility on the homepage and a representative docs page.</li><li>Add page titles, descriptions, canonical metadata, social previews, and a sitemap where supported.</li><li>Do not add third-party analytics by default.</li></ul><h2 id="ui-flows" tabindex="-1">UI flows <a class="header-anchor" href="#ui-flows" aria-label="Permalink to &quot;UI flows&quot;">​</a></h2><h3 id="learn-what-sovereign-is" tabindex="-1">Learn what Sovereign is <a class="header-anchor" href="#learn-what-sovereign-is" aria-label="Permalink to &quot;Learn what Sovereign is&quot;">​</a></h3><ol><li>A visitor lands on the homepage and reads the product category and outcome.</li><li>The product visual and model explain an instance with users and apps.</li><li>The visitor reviews available capabilities without confusing planned work with shipped behavior.</li><li>The visitor chooses to try, host, build, or read technical documentation.</li></ol><h3 id="find-an-instance" tabindex="-1">Find an instance <a class="header-anchor" href="#find-an-instance" aria-label="Permalink to &quot;Find an instance&quot;">​</a></h3><ol><li>A visitor opens <strong>Instances</strong>.</li><li>The page explains independent operation and the project&#39;s trust boundary.</li><li>The visitor reviews operator, audience, access policy, apps, policies, and verification date.</li><li>The visitor follows the external link and registers only under the operator&#39;s stated policy.</li></ol><h3 id="host-an-instance" tabindex="-1">Host an instance <a class="header-anchor" href="#host-an-instance" aria-label="Permalink to &quot;Host an instance&quot;">​</a></h3><ol><li>A visitor chooses <strong>Host your own</strong>.</li><li>The operator guide distinguishes evaluation from production operation.</li><li>The visitor reviews operational responsibilities and prerequisites.</li><li>The visitor follows the existing deployment guide and then production, security, backup, and upgrade guidance.</li></ol><h3 id="install-and-enable-notifications" tabindex="-1">Install and enable notifications <a class="header-anchor" href="#install-and-enable-notifications" aria-label="Permalink to &quot;Install and enable notifications&quot;">​</a></h3><ol><li>A user opens their instance in a supported browser.</li><li>The user installs that instance to the Home Screen, app launcher, or desktop.</li><li>The user launches the installed app and opens Account → Notifications.</li><li>The user enables push on that device and grants the browser or OS permission.</li><li>The user can later mute categories or remove the device subscription.</li></ol><h3 id="build-a-custom-app" tabindex="-1">Build a custom app <a class="header-anchor" href="#build-a-custom-app" aria-label="Permalink to &quot;Build a custom app&quot;">​</a></h3><ol><li>A visitor chooses <strong>Build an app</strong>.</li><li>The page explains that user-facing apps are delivered as plugins.</li><li>The developer sees which shared capabilities are currently available.</li><li>The developer follows the plugin quickstart, SDK, data, UI, testing, and distribution documentation.</li></ol><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><h3 id="keep-the-technical-homepage-and-add-one-product-page" tabindex="-1">Keep the technical homepage and add one product page <a class="header-anchor" href="#keep-the-technical-homepage-and-add-one-product-page" aria-label="Permalink to &quot;Keep the technical homepage and add one product page&quot;">​</a></h3><p>Rejected because the first page would still require prior product knowledge and would continue to hide the user journey.</p><h3 id="build-a-separate-marketing-application" tabindex="-1">Build a separate marketing application <a class="header-anchor" href="#build-a-separate-marketing-application" aria-label="Permalink to &quot;Build a separate marketing application&quot;">​</a></h3><p>Rejected because it would duplicate navigation, content, deployment, search, and visual maintenance. VitePress already provides the required static-site and documentation foundation.</p><h3 id="call-sovereign-an-app-suite" tabindex="-1">Call Sovereign an app suite <a class="header-anchor" href="#call-sovereign-an-app-suite" aria-label="Permalink to &quot;Call Sovereign an app suite&quot;">​</a></h3><p>Rejected because a suite implies a fixed bundle. The runtime and reusable platform capabilities are central to the product.</p><h3 id="automatically-discover-public-instances" tabindex="-1">Automatically discover public instances <a class="header-anchor" href="#automatically-discover-public-instances" aria-label="Permalink to &quot;Automatically discover public instances&quot;">​</a></h3><p>Rejected for the first release because discovery, verification, abuse handling, health checks, metadata exposure, and delisting require a separate operational and security design.</p><h3 id="publish-the-engineering-roadmap-directly" tabindex="-1">Publish the engineering roadmap directly <a class="header-anchor" href="#publish-the-engineering-roadmap-directly" aria-label="Permalink to &quot;Publish the engineering roadmap directly&quot;">​</a></h3><p>Rejected because internal task ordering, identifiers, and experimental work are not a stable product commitment and are difficult for non-contributors to interpret.</p><h2 id="open-questions" tabindex="-1">Open questions <a class="header-anchor" href="#open-questions" aria-label="Permalink to &quot;Open questions&quot;">​</a></h2><ol><li>Is <code>sovereign.openfs.io</code> a production, approval-based, invite-only, or demonstration instance, and who is its public operator?</li><li>Which privacy, terms, support, and registration-policy links may be published for that instance?</li><li>Which product workflows and screenshots are stable enough for the homepage?</li><li>Which capabilities belong in each public status at launch, particularly encryption-related capabilities?</li><li>Who owns ongoing review of product claims, screenshots, instance listings, and public roadmap horizons?</li><li>Will GitHub Pages remain the canonical domain after the revamp?</li></ol><p>These questions can narrow later content without blocking the initial site foundation and route structure. Unknown instance facts must remain visibly unknown rather than being inferred.</p><h2 id="adoption-path" tabindex="-1">Adoption path <a class="header-anchor" href="#adoption-path" aria-label="Permalink to &quot;Adoption path&quot;">​</a></h2><ol><li>Land this RFC and retain the comprehensive internal planning document as implementation context.</li><li>Introduce the product-led theme, homepage, navigation, and audience hubs.</li><li>Add product education, getting-started, candidate instance, and public roadmap pages using verified claims only.</li><li>Reorganize technical documentation incrementally while preserving routes.</li><li>Add structured directory validation before accepting more than the initial candidate entry.</li><li>Complete browser, accessibility, performance, link, and metadata review before publishing the revamp.</li></ol><p>This change affects only the docs site and prose. It does not require a root, SDK, or UI package version bump. Epics and <code>ROADMAP.md</code> remain unchanged.</p><h2 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Version</th><th>Date</th><th>Change</th></tr></thead><tbody><tr><td>0.1</td><td>July 2026</td><td>Initial draft</td></tr></tbody></table>`,94)])])}const m=a(o,[["render",s]]);export{h as __pageData,m as default};
